@page "/dashboard"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3 row">
    <div class="col-md-4">
        <input class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="PickedUp">Picked Up</option>
            <option value="InTransit">In Transit</option>
            <option value="OutForDelivery">Out for Delivery</option>
            <option value="Delivered">Delivered</option>
            <option value="Exception">Exception</option>
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-success btn-sm" @onclick="CreateShipment">Create</button>
                <button class="btn btn-secondary btn-sm" @onclick="() => showCreateForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p>Loading shipments...</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Customer</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(s.Status)">@s.Status</span></td>
                    <td>@s.CustomerEmail</td>
                    <td>@s.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                            @onchange="e => UpdateStatus(s, e.Value?.ToString() ?? s.Status)">
                            <option value="Pending">Pending</option>
                            <option value="PickedUp">Picked Up</option>
                            <option value="InTransit">In Transit</option>
                            <option value="OutForDelivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Exception">Exception</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private ShipmentDto newShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments => shipments?
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter)
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new ShipmentDto { Status = "Pending" };
    }

    private async Task CreateShipment()
    {
        newShipment.TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
        newShipment.CreatedDate = DateTime.UtcNow;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        showCreateForm = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
        shipment.Status = newStatus;
    }

    private static string GetStatusColor(string status) => status switch
    {
        "Pending" => "secondary",
        "PickedUp" => "info",
        "InTransit" => "primary",
        "OutForDelivery" => "warning",
        "Delivered" => "success",
        "Exception" => "danger",
        _ => "secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., TRK-20260525-1234)"
                @bind="trackingNumber" @onkeyup="HandleKeyUp" />
            <button class="btn btn-primary" @onclick="SearchShipment">Track</button>
        </div>
    </div>
</div>

@if (isLoading)
{
    <p>Searching...</p>
}
else if (searched && shipment is null)
{
    <div class="alert alert-warning">No shipment found with tracking number: @trackingNumber</div>
}
else if (shipment is not null)
{
