                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(s.Status)">@s.Status</span></td>
                    <td>@s.CustomerEmail</td>
                    <td>@s.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                            @onchange="e => UpdateStatus(s, e.Value?.ToString() ?? s.Status)">
                            <option value="Pending">Pending</option>
                            <option value="PickedUp">Picked Up</option>
                            <option value="InTransit">In Transit</option>
                            <option value="OutForDelivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Exception">Exception</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private ShipmentDto newShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments => shipments?
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter)
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new ShipmentDto { Status = "Pending" };
    }

    private async Task CreateShipment()
    {
        newShipment.TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
        newShipment.CreatedDate = DateTime.UtcNow;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        showCreateForm = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
        shipment.Status = newStatus;
    }

    private static string GetStatusColor(string status) => status switch
    {
        "Pending" => "secondary",
        "PickedUp" => "info",
        "InTransit" => "primary",
        "OutForDelivery" => "warning",
        "Delivered" => "success",
        "Exception" => "danger",
        _ => "secondary"
    };
}
```

