@code {
    private string trackingNumber = "";
    private ShipmentDto? shipment;
    private bool searched;
    private bool isLoading;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isLoading = true;
        searched = true;
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        isLoading = false;
    }

    private async Task HandleKeyUp(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await SearchShipment();
    }

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out for Delivery",
        _ => status
    };

    private static int GetProgress(string status) => status switch
    {
        "Pending" => 10,
        "PickedUp" => 30,
        "InTransit" => 55,
        "OutForDelivery" => 80,
        "Delivered" => 100,
        "Exception" => 50,
        _ => 0
    };

    private static string GetStatusColor(string status) => status switch
    {
        "Pending" => "secondary",
        "PickedUp" => "info",
        "InTransit" => "primary",
        "OutForDelivery" => "warning",
        "Delivered" => "success",
        "Exception" => "danger",
        _ => "secondary"
    };
}
```

